// Package main implements a simple webserver that takes an uploaded file from /upload and saves it in /files
package main

import (
    "io"
    "log"
    "net/http"
    "os"
    "github.com/gorilla/mux"

    // This import is necessary to use the gorilla mux router, the router used by the webserver implementation.
    _ "github.com/gorilla/handlers"
)


// SaveFile stores the file uploaded in /upload path to the /files/<filename> path on the server and returns <filename> as response 
func SaveFile(w http.ResponseWriter, r *http.Request){
   r.ParseMultipartForm(32 << 20) //ParseMultipartForm takes the maxMemory size for parsing form file
   file, handler, err := r.FormFile("file")
    if err != nil {
            log.Println("Error Retrieving the File", err)
            return
        }
        defer file.Close()

        f, err := os.OpenFile("/files/"+handler.Filename, os.O_WRONLY|os.O_CREATE, 0666)
        if err != nil {
                log.Println(err)
                return
            }
            defer f.Close()

            io.Copy(f, file)
            w.Write([]byte("Your File has been Uploaded!!"))
}


func main(){
  r := mux.NewRouter().StrictSlash(true);

  //Path to our static content
  r.Handle("/", http.FileServer(http.Dir("./static")))

  //The router registers our /upload path and a GET method that takes an html form, with file type inputs
  r.HandleFunc("/upload", savefile).Methods("GET")

  //Start server on port 8080
  log.Fatal(http.ListenAndServe(":8080", r))
}